8→export function NavigationProvider({ children }: { children: React.ReactNode }) {
9→  const [currentSection, setCurrentSection] = useState<NavigationSection>('home');
10→  const [isResumeOpen, setIsResumeOpen] = useState(false);
11→  const [selectedCertification, setSelectedCertification] = useState<CertificationItem | null>(null);
12→  const [isCertModalOpen, setIsCertModalOpen] = useState(false);
13→
14→  const handleSectionChange = useCallback((section: NavigationSection) => {
15→    setCurrentSection(section);
16→  }, []);
17→
18→  const openResume = useCallback(() => {
19→    setIsResumeOpen(true);
20→  }, []);
21→
22→  const closeResume = useCallback(() => {
23→    setIsResumeOpen(false);
24→  }, []);
25→
26→  const openCertModal = useCallback((cert: CertificationItem) => {
27→    setSelectedCertification(cert);
28→    setIsCertModalOpen(true);
29→  }, []);
30→
31→  const closeCertModal = useCallback(() => {
32→    setIsCertModalOpen(false);
33→    setSelectedCertification(null);
34→  }, []);
35→
36→  const value: NavigationContextType = {
37→    currentSection,
38→    setCurrentSection: handleSectionChange,
39→    isResumeOpen,
40→    openResume,
41→    closeResume,
42→    selectedCertification,
43→    isCertModalOpen,
44→    openCertModal,
